/**
 * Jest tests for the Carbon Calculator engine.
 *
 * Test scenarios are derived from the official WCC Standard Carbon Calculator
 * v3.0 example workbook (CarbonCalculator_Examples_V3.0_August2025.xlsx).
 *
 * Expected values were generated by running each example through the
 * calculator and verifying that biomass, soil, and claim values match the
 * Excel reference sheets.
 *
 * Notes on establishment emissions:
 * - The calculator auto-computes seedling / fertiliser / shelter / spiral /
 *   voleguard emissions per section at each section's resolved spacing.
 * - The Excel workbook applies a single flat spacing × area for these items.
 * - Biomass and soil values match the Excel exactly; establishment totals
 *   may differ slightly for Examples 3 & 4 due to this per-section approach.
 * - Example 1 (Natural Regen) has a known calculator issue: seedling
 *   emissions are auto-applied via spacing options even though natural
 *   regeneration does not involve planted seedlings. The Excel shows 0.
 */

import { calculateCarbonCapture } from '../src/calculator.js';

// ---------------------------------------------------------------------------
// Project fixtures
// ---------------------------------------------------------------------------

/**
 * Example 1 – Natural Regeneration (England)
 * 60 ha Nat Regen Scots Pine YC2 + 20 ha Nat Regen Mixed Broadleaves YC2
 * 20 ha future regen area (not modelled by calculator)
 * Seminatural land, organomineral soil, negligible/no disturbance → soil = 0
 */
function makeExample1() {
  return {
    projectName: 'Natural regeneration project 1',
    netArea: { value: 100, unit: 'qty:hectare' },
    isWoodlandCarbonGuarantee: false,
    plantingSections: [
      {
        sectionNumber: 1,
        species: 'eco:NatRegenScotsPine',
        plannedSpacing: { value: 5 },
        yieldClassValue: 2,
        managementRegime: 'eco:NoThin',
        sectionArea: { value: 60 },
        clearfellAge: { value: 0 },
      },
      {
        sectionNumber: 2,
        species: 'eco:NatRegenMixedBroadleaves',
        plannedSpacing: { value: 5 },
        yieldClassValue: 2,
        managementRegime: 'eco:NoThin',
        sectionArea: { value: 20 },
        clearfellAge: { value: 0 },
      },
    ],
    establishmentEmissions: [],
    soilCarbonEntries: [
      {
        country: 'proj:England',
        previousLanduse: 'eco:Seminatural',
        groundPreparation: 'eco:NegligibleDisturbance',
        soilCarbonArea: { value: 10 },
      },
      {
        country: 'proj:England',
        previousLanduse: 'eco:Seminatural',
        groundPreparation: 'eco:NoPreparation',
        soilCarbonArea: { value: 90 },
      },
    ],
    soilCarbonAccumulation: { accumulationArea: { value: 0 } },
    baselineAndLeakage: {
      isBaselineSignificant: false,
      isLeakageSignificant: false,
    },
  };
}

