// ---------------------------------------------------------------------------
// Helper: get period by 1-based index
// ---------------------------------------------------------------------------
function getPeriod(result, idx) {
  return result.periodResults[idx - 1];
}

// =========================================================================
// Tests
// =========================================================================

describe('Carbon Calculator – Excel Example Scenarios', () => {
  // -----------------------------------------------------------------------
  // Example 1 – Natural Regeneration
  // -----------------------------------------------------------------------
  describe('Example 1 – Natural Regeneration', () => {
    let result;
    beforeAll(() => {
      result = calculateCarbonCapture(makeExample1());
    });

    it('should produce no errors', () => {
      expect(result.errors).toEqual([]);
    });

    it('should resolve correct lookup keys', () => {
      const keys = result.sections.map(s => s.lookupKey);
      expect(keys).toEqual(['NP5.002No_thin', 'NB5.002No_thin']);
    });

    it('should resolve correct species labels', () => {
      expect(result.sections[0].species).toBe('Nat Regen - Scots Pine');
      expect(result.sections[1].species).toBe('Nat Regen - Mixed Broadleaves');
    });

    it('should have zero soil emissions (seminatural land)', () => {
      expect(result.summary.soilEmissionYear0).toBe(0);
    });

    it('should produce 20 period results', () => {
      expect(result.periodResults).toHaveLength(20);
    });

    it('should match biomass carbon at key periods', () => {
      // Biomass values match the Excel exactly
      expect(getPeriod(result, 1).totalBiomass).toBe(0);           // Y5 – no growth yet
      expect(getPeriod(result, 2).totalBiomass).toBe(9.44);        // Y10
      expect(getPeriod(result, 5).totalBiomass).toBe(479.96);      // Y25
      expect(getPeriod(result, 10).totalBiomass).toBe(2487.09);    // Y50
      expect(getPeriod(result, 20).totalBiomass).toBe(4589.04);    // Y100
    });

    it('should match net carbon after buffer at key periods', () => {
      expect(getPeriod(result, 1).netAfterBuffer).toBe(-4);        // Y5
      expect(getPeriod(result, 5).netAfterBuffer).toBe(303);       // Y25
      expect(getPeriod(result, 10).netAfterBuffer).toBe(1588);     // Y50
      expect(getPeriod(result, 20).netAfterBuffer).toBe(2933);     // Y100
    });

    it('should compute per-hectare correctly at Y100', () => {
      expect(getPeriod(result, 20).perHectare).toBe(29.33);
    });

    it('should have correct summary totals', () => {
      expect(result.summary.totalProjectArea).toBe(100);
      expect(result.summary.numberOfSections).toBe(2);
      expect(result.summary.totalNetCarbon100yr).toBe(3666);
      expect(result.summary.totalNetAfterBuffer100yr).toBe(2933);
    });
  });

  // -----------------------------------------------------------------------
  // Example 2 – Broadleaved Minimum Intervention
  // -----------------------------------------------------------------------
  describe('Example 2 – Broadleaved Minimum Intervention', () => {
    let result;
    beforeAll(() => {
      result = calculateCarbonCapture(makeExample2());
    });

    it('should produce no errors', () => {
      expect(result.errors).toEqual([]);
    });

    it('should resolve correct lookup keys', () => {
      const keys = result.sections.map(s => s.lookupKey);
      expect(keys).toEqual([
        'OK3.004No_thin',
        'SA3.006No_thin',
        'SA3.002No_thin',
        'BE3.006No_thin',
      ]);
    });

    it('should resolve 4 sections', () => {
      expect(result.sections).toHaveLength(4);
      expect(result.sections[0].species).toBe('Oak (robur/petraea)');
      expect(result.sections[1].species).toBe('Birch (downy/silver)');
      expect(result.sections[2].species).toBe('Common alder');
      expect(result.sections[3].species).toBe('Sweet chestnut');
    });

    it('should calculate establishment emissions matching Excel', () => {
      // Exact match: -556.08 (Excel: -556.08067)
      expect(result.summary.totalEstablishmentEmissions).toBeCloseTo(-556.08, 1);
    });

    it('should calculate soil emissions matching Excel', () => {
      // Exact match: -1191.67 (Excel: -1191.66667)
      expect(result.summary.soilEmissionYear0).toBeCloseTo(-1191.67, 1);
    });

    it('should match biomass carbon at key periods (Excel-verified)', () => {
      expect(getPeriod(result, 1).totalBiomass).toBe(141.25);       // Y5
      expect(getPeriod(result, 5).totalBiomass).toBe(14566.5);      // Y25
      expect(getPeriod(result, 10).totalBiomass).toBe(52794.25);    // Y50
      expect(getPeriod(result, 15).totalBiomass).toBe(64197.55);    // Y75
      expect(getPeriod(result, 20).totalBiomass).toBe(72983.4);     // Y100
    });

    it('should match adjusted biomass (× 0.8) at key periods', () => {
      expect(getPeriod(result, 1).adjustedBiomass).toBe(113);
      expect(getPeriod(result, 10).adjustedBiomass).toBe(42235.4);
      expect(getPeriod(result, 20).adjustedBiomass).toBe(58386.72);
    });

    it('should match net carbon after buffer (claimable) at all periods', () => {
      const expected = [
        -1308, -972, 179, 3437, 7924, 13815, 21877, 27003, 30150, 32390,
        34112, 35578, 37014, 38379, 39688, 40890, 42066, 43212, 44349, 45311,
      ];
      const actual = result.periodResults.map(p => p.netAfterBuffer);
      expect(actual).toEqual(expected);
    });

    it('should match per-hectare at Y100', () => {
      expect(getPeriod(result, 20).perHectare).toBe(453.11);
    });

    it('should have correct summary', () => {
      expect(result.summary.totalNetCarbon100yr).toBe(56639);
      expect(result.summary.totalNetAfterBuffer100yr).toBe(45311);
      expect(result.summary.totalBuffer100yr).toBe(11328);
    });
  });

  // -----------------------------------------------------------------------
  // Example 3 – Mixed Conifer Thinned
  // -----------------------------------------------------------------------
  describe('Example 3 – Mixed Conifer Thinned', () => {
    let result;
    beforeAll(() => {
      result = calculateCarbonCapture(makeExample3());
    });

    it('should produce no errors', () => {
      expect(result.errors).toEqual([]);
    });

    it('should resolve correct lookup keys', () => {
      const keys = result.sections.map(s => s.lookupKey);
      expect(keys).toEqual([
        'SS2.024Thinned',
        'DF1.718Thinned',
        'HL1.714Thinned',
        'OK3.004No_thin',
        'SA3.004No_thin',
      ]);
    });

    it('should resolve DF spacing 2.0→1.7 (closest available)', () => {
      // Douglas fir model group has spacing options: 1.7 is closest to 2.0
      expect(result.sections[1].spacing).toBe(1.7);
    });

    it('should resolve HL spacing 2.0→1.7 (closest available)', () => {
      expect(result.sections[2].spacing).toBe(1.7);
    });

    it('should calculate soil emissions to -3630', () => {
      // 30 ha × 0 + 20 ha × -16.5 + 50 ha × -66 = -3630
      expect(result.summary.soilEmissionYear0).toBe(-3630);
    });

    it('should match biomass carbon at key periods', () => {
      expect(getPeriod(result, 1).totalBiomass).toBe(1439);         // Y5
      expect(getPeriod(result, 5).totalBiomass).toBe(24833.3);      // Y25
      expect(getPeriod(result, 10).totalBiomass).toBe(57032.6);     // Y50
      expect(getPeriod(result, 20).totalBiomass).toBe(77205.5);     // Y100
    });

    it('should match net carbon after buffer at all periods', () => {
      const expected = [
        -2087, 228, 5280, 8872, 12886, 17996, 23757, 27845, 30858, 33493,
        35529, 37442, 39163, 40654, 41940, 43118, 44106, 44939, 45831, 46403,
      ];
      const actual = result.periodResults.map(p => p.netAfterBuffer);
      expect(actual).toEqual(expected);
    });

    it('should have correct summary', () => {
      expect(result.summary.numberOfSections).toBe(5);
      expect(result.summary.totalNetCarbon100yr).toBe(58004);
      expect(result.summary.totalNetAfterBuffer100yr).toBe(46403);
      expect(result.summary.perHectare100yr).toBe(464.03);
    });
  });

  // -----------------------------------------------------------------------
  // Example 4 – Conifer Clearfell
  // -----------------------------------------------------------------------
  describe('Example 4 – Conifer Clearfell', () => {
    let result;
    beforeAll(() => {
      result = calculateCarbonCapture(makeExample4());
    });

    it('should produce no errors', () => {
      expect(result.errors).toEqual([]);
    });

    it('should resolve correct lookup keys', () => {
      const keys = result.sections.map(s => s.lookupKey);
      expect(keys).toEqual([
        'SS2.024Thinned',
        'DF1.718Thinned',
        'OK3.004No_thin',
        'SA3.004No_thin',
      ]);
    });

    it('should set clearfell caps on conifer sections', () => {
      // SS clearfell at age 40 → cap from clearfell lookup table
      expect(result.sections[0].clearfellAge).toBe(40);
      expect(result.sections[0].clearfellCap).toBeGreaterThan(0);
      // DF clearfell at age 50
      expect(result.sections[1].clearfellAge).toBe(50);
      expect(result.sections[1].clearfellCap).toBeGreaterThan(0);
      // Broadleaved sections – no clearfell
      expect(result.sections[2].clearfellCap).toBeNull();
      expect(result.sections[3].clearfellCap).toBeNull();
    });

    it('should calculate soil emissions to -2933.33', () => {
      expect(result.summary.soilEmissionYear0).toBeCloseTo(-2933.33, 1);
    });

    it('should match biomass carbon at key periods', () => {
      expect(getPeriod(result, 1).totalBiomass).toBe(1058.3);       // Y5
      expect(getPeriod(result, 5).totalBiomass).toBe(20887.5);      // Y25
      expect(getPeriod(result, 10).totalBiomass).toBe(39181.25);    // Y50
      expect(getPeriod(result, 20).totalBiomass).toBe(47908.25);    // Y100
    });

    it('should cap biomass growth for clearfell sections', () => {
      // After clearfell age, per-ha biomass should be capped.
      // Total biomass still grows (broadleaved sections keep growing)
      // but the total is much lower than it would be without clearfell caps.
      const p8 = getPeriod(result, 8);   // Y40 – SS clearfell age
      const p10 = getPeriod(result, 10); // Y50 – DF clearfell age
      const p20 = getPeriod(result, 20); // Y100

      expect(p20.totalBiomass).toBeGreaterThan(p10.totalBiomass);
      expect(p20.totalBiomass).toBeLessThan(60000); // would be >60k without caps
    });

    it('should match net carbon after buffer at all periods', () => {
      const expected = [
        -1810, -28, 4852, 8290, 10881, 13625, 17348, 19650, 21238, 22589,
        23431, 24097, 24720, 25255, 25769, 26254, 26722, 27171, 27822, 28174,
      ];
      const actual = result.periodResults.map(p => p.netAfterBuffer);
      expect(actual).toEqual(expected);
    });

    it('should have correct summary', () => {
      expect(result.summary.numberOfSections).toBe(4);
      expect(result.summary.totalNetCarbon100yr).toBe(35218);
      expect(result.summary.totalNetAfterBuffer100yr).toBe(28174);
      expect(result.summary.perHectare100yr).toBe(281.74);
    });
  });
});

// =========================================================================
// Calculator Mechanics Tests
// =========================================================================

describe('Carbon Calculator – Mechanics', () => {
  describe('Model precision factor', () => {
    it('should apply 0.8 factor to raw biomass', () => {
      const result = calculateCarbonCapture(makeExample2());
      const p1 = getPeriod(result, 1);
      expect(p1.adjustedBiomass).toBeCloseTo(p1.totalBiomass * 0.8, 2);
    });
  });

  describe('Buffer deduction', () => {
    it('should withhold 20% of net carbon as buffer', () => {
      const result = calculateCarbonCapture(makeExample2());
      for (const p of result.periodResults) {
        expect(p.bufferDeduction).toBe(Math.round(p.netCarbon * 0.2));
        expect(p.netAfterBuffer).toBe(p.netCarbon - p.bufferDeduction);
      }
    });
  });

  describe('Gross sequestration', () => {
    it('should equal adjustedBiomass + est + soil for each period', () => {
      const result = calculateCarbonCapture(makeExample2());
      for (const p of result.periodResults) {
        const expected = p.adjustedBiomass + p.establishmentEmissions + p.totalSoilCarbon;
        expect(p.grossSequestration).toBeCloseTo(expected, 1);
      }
    });
  });

  describe('Vintage schedule', () => {
    it('should produce 10 vintages for standard (10-yearly) verification', () => {
      const result = calculateCarbonCapture(makeExample2());
      expect(result.vintageSchedule).toHaveLength(10);
    });

    it('should produce 20 vintages for guarantee (5-yearly) verification', () => {
      const project = makeExample2();
      project.isWoodlandCarbonGuarantee = true;
      const result = calculateCarbonCapture(project);
      expect(result.vintageSchedule).toHaveLength(20);
    });

    it('should not issue negative PIUs', () => {
      const result = calculateCarbonCapture(makeExample2());
      for (const v of result.vintageSchedule) {
        expect(v.periodIncrement).toBeGreaterThanOrEqual(0);
        expect(v.totalPIUsIssued).toBeGreaterThanOrEqual(0);
      }
    });
  });

  describe('Establishment emissions', () => {
    it('should be constant across all periods (one-time cost)', () => {
      const result = calculateCarbonCapture(makeExample2());
      const estValues = result.periodResults.map(p => p.establishmentEmissions);
      const unique = new Set(estValues);
      expect(unique.size).toBe(1);
    });

    it('should include both fixed-rate and auto-computed items', () => {
      // Project with herbicide (fixed rate) and seedlings (auto per section)
      const project = {
        plantingSections: [{
          sectionNumber: 1,
          species: 'eco:SitkaSpruce',
          plannedSpacing: { value: 2 },
          yieldClassValue: 12,
          managementRegime: 'eco:NoThin',
          sectionArea: { value: 10 },
          clearfellAge: { value: 0 },
        }],
        establishmentEmissions: [
          { emissionType: 'proj:HerbicideEmission', inputQuantity: { value: 100 } },
        ],
        soilCarbonEntries: [],
        soilCarbonAccumulation: { accumulationArea: { value: 0 } },
        baselineAndLeakage: { isBaselineSignificant: false, isLeakageSignificant: false },
      };
      const result = calculateCarbonCapture(project);
      // Fixed herbicide: -0.04414 × 100 = -4.414
      // Auto seedlings for 10 ha at 2.0 m spacing: -0.375 × 10 = -3.75
      // Total ≈ -8.164
      expect(result.summary.totalEstablishmentEmissions).toBeCloseTo(-8.16, 0);
    });
  });
});

